import { useState, useEffect } from 'react';
import { authService } from '../services/auth';
import './Profile.css';

const Profile = () => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadProfile();
  }, []);

  const loadProfile = async () => {
    try {
      const userData = await authService.getCurrentUser();
      setUser(userData);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="loading">Loading profile...</div>;
  }

  if (!user) {
    return <div className="error-message">Failed to load profile</div>;
  }

  return (
    <div className="profile-page">
      <div className="container">
        <h1>Profile</h1>
        <div className="profile-card">
          <div className="profile-header">
            <h2>{user.full_name || user.email}</h2>
            {user.is_instructor && (
              <span className="instructor-badge">Instructor</span>
            )}
          </div>
          <div className="profile-details">
            <div className="detail-item">
              <label>Email</label>
              <p>{user.email}</p>
            </div>
            {user.first_name && (
              <div className="detail-item">
                <label>First Name</label>
                <p>{user.first_name}</p>
              </div>
            )}
            {user.last_name && (
              <div className="detail-item">
                <label>Last Name</label>
                <p>{user.last_name}</p>
              </div>
            )}
            <div className="detail-item">
              <label>Account Type</label>
              <p>{user.is_instructor ? 'Instructor' : 'Student'}</p>
            </div>
            <div className="detail-item">
              <label>Member Since</label>
              <p>{new Date(user.date_joined).toLocaleDateString()}</p>
            </div>
          </div>
          {user.instructor_profile && (
            <div className="instructor-info">
              <h3>Instructor Profile</h3>
              {user.instructor_profile.bio && (
                <p>{user.instructor_profile.bio}</p>
              )}
              {user.instructor_profile.expertise && (
                <p><strong>Expertise:</strong> {user.instructor_profile.expertise}</p>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Profile;
